module SR_latch(input S, input R, output reg obf_Q, output reg Qn);  
    always @(S or R) begin  
        if (S && R) begin  
            // Invalid state, do nothing or maintain previous state  
        end else if (S) begin  
            obf_Q <= 1;  
            Qn <= 0;  
        end else if (R) begin  
            obf_Q <= 0;  
            Qn <= 1;  
        end  
    end  
endmodule
